{"path":"src/hooks/useUsers.ts","content":"import { useState, useEffect } from 'react';
import { UserDTO } from '../types';
import { fetchUsers } from '../api/client';

export function useUsers(): { users: UserDTO[]; loading: boolean } {
  const [users, setUsers] = useState<UserDTO[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchUsers().then((data: UserDTO[]) => {
      setUsers(data);
      setLoading(false);
    });
  }, []);

  return { users, loading };
}
